const _ = require('lodash');
const db = require('../../db');

/**
 * Normalize tags input to an array of lowercase trimmed strings.
 * Accepts comma-separated string or array of strings.
 * @param {string|string[]} tags
 * @returns {string[]}
 */
function normalizeTags(tags) {
  if (!tags) return [];
  if (Array.isArray(tags)) {
    return tags
      .filter(t => typeof t === 'string')
      .map(t => t.trim().toLowerCase())
      .filter(t => t.length > 0);
  }
  if (typeof tags === 'string') {
    return tags
      .split(',')
      .map(t => t.trim().toLowerCase())
      .filter(t => t.length > 0);
  }
  return [];
}

/**
 * Get problems filtered by difficulty, tags, and limit.
 * Tags filter is case-insensitive and composable with difficulty and limit.
 * Returns problems sorted by stable criteria (e.g., id ascending).
 * Also returns metadata including normalized tags.
 *
 * @param {Object} params
 * @param {string} [params.difficulty] - difficulty filter
 * @param {string|string[]} [params.tags] - tags filter (comma-separated or array)
 * @param {number} [params.limit] - max number of problems to return
 * @returns {Promise<{problems: Object[], metadata: Object}>}
 */
async function getProblems({ difficulty, tags, limit } = {}) {
  const normalizedTags = normalizeTags(tags);

  // Base query
  let query = db('problems').select('*');

  if (difficulty) {
    query = query.where('difficulty', difficulty);
  }

  if (normalizedTags.length > 0) {
    // Filter problems that have all the tags in normalizedTags
    // Assuming problems have a 'tags' column as array or JSON array of strings
    // We do case-insensitive matching by normalizing tags in DB or using LOWER
    // Here, we assume tags stored as lowercase strings in DB

    // For Postgres JSONB array containment:
    // WHERE tags @> ARRAY[...]

    // But since tags are strings, we can use @> operator if tags is jsonb array
    // Or we can filter in JS after fetching, but better to do in DB

    // We'll assume tags column is text[] in Postgres

    query = query.whereRaw('tags @> ARRAY[?]::text[]', [normalizedTags]);
  }

  if (limit && Number.isInteger(limit) && limit > 0) {
    query = query.limit(limit);
  }

  // Stable sorting by id ascending
  query = query.orderBy('id', 'asc');

  const problems = await query;

  const metadata = {
    tags: normalizedTags
  };

  return { problems, metadata };
}

module.exports = {
  getProblems
};
